<template lang="html">
  <div id="main">
    <nav class="navbar is-fixed-top" role="navigation" aria-label="main navigation">
  <div class="navbar-brand">
    <a class="navbar-item" href="/">
      <strong>Zhaolin Lau</strong>
    </a>

    <a role="button" class="navbar-burger" aria-label="menu" aria-expanded="false" data-target="navbar">
      <span aria-hidden="true"></span>
      <span aria-hidden="true"></span>
      <span aria-hidden="true"></span>
    </a>
  </div>

  <div id="navbar" class="navbar-menu has-text-centered">
    <div class="navbar-start">
      <a class="navbar-item" href="#main">
        Home
      </a>

      <a class="navbar-item" href="#about">
        About
      </a>

      <a class="navbar-item" href="#works">
        Works
      </a>

      <a class="navbar-item" href="#contact">
        Contact
      </a>
    </div>
  </div>
</nav>
<div class="hero is-primary is-fullheight is-bold">
  <div class="hero-body">
    <div class="container content is-large has-text-centered">
      <h1>Main</h1>
    </div>
  </div>
</div>
  </div>
</template>

<script>
document.addEventListener('DOMContentLoaded', () => {

  // Get all "navbar-burger" elements
  const $navbarBurgers = Array.prototype.slice.call(document.querySelectorAll('.navbar-burger'), 0);

  // Check if there are any navbar burgers
  if ($navbarBurgers.length > 0) {

    // Add a click event on each of them
    $navbarBurgers.forEach( el => {
      el.addEventListener('click', () => {

        // Get the target from the "data-target" attribute
        const target = el.dataset.target;
        const $target = document.getElementById(target);

        // Toggle the "is-active" class on both the "navbar-burger" and the "navbar-menu"
        el.classList.toggle('is-active');
        $target.classList.toggle('is-active');
      });
    });
  }
});
</script>
